import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"API Keys","description":"","frontmatter":{},"headers":[],"relativePath":"guide/api-keys.md","filePath":"guide/api-keys.md"}'),s={name:"guide/api-keys.md"};function i(d,e,l,n,h,c){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="api-keys" tabindex="-1">API Keys <a class="header-anchor" href="#api-keys" aria-label="Permalink to &quot;API Keys&quot;">​</a></h1><p>Most sources don&#39;t need keys. <strong>13 sources do</strong> — all free, all self-serve. Keys live in your browser&#39;s <code>localStorage</code> and are sent only to the API they belong to.</p><p>You can use InspoSearch productively with zero keys. Adding keys unlocks more sources and better AI analysis options, not core functionality.</p><h2 id="tl-dr-—-the-four-keys-worth-getting-first" tabindex="-1">TL;DR — the four keys worth getting first <a class="header-anchor" href="#tl-dr-—-the-four-keys-worth-getting-first" aria-label="Permalink to &quot;TL;DR — the four keys worth getting first&quot;">​</a></h2><p>If you only want to add a few, start here:</p><ol><li><strong>Europeana</strong> — unlocks ~60% of the dynamically-discovered sources (2,000+ European cultural providers via a single key). Highest ROI by far</li><li><strong>Unsplash</strong> — the main general-photography unlock</li><li><strong>Rijksmuseum</strong> — high-quality, high-resolution Dutch and European art</li><li><strong>Harvard Art Museums</strong> — deep research metadata</li></ol><p>Everything else is incremental.</p><h2 id="full-list" tabindex="-1">Full list <a class="header-anchor" href="#full-list" aria-label="Permalink to &quot;Full list&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Category</th><th style="text-align:center;">Free?</th><th>Where to get a key</th></tr></thead><tbody><tr><td>Europeana</td><td>Historical</td><td style="text-align:center;">Yes</td><td><a href="https://pro.europeana.eu/page/get-api" target="_blank" rel="noreferrer">pro.europeana.eu/page/get-api</a></td></tr><tr><td>Digital Public Library of America</td><td>Historical</td><td style="text-align:center;">Yes</td><td><a href="https://dp.la/info/developers/codex" target="_blank" rel="noreferrer">dp.la/info/developers/codex</a></td></tr><tr><td>National Library of Australia (Trove)</td><td>Historical</td><td style="text-align:center;">Yes</td><td><a href="https://trove.nla.gov.au/about/create-something/using-api" target="_blank" rel="noreferrer">trove.nla.gov.au/about/create-something/using-api</a></td></tr><tr><td>Rijksmuseum</td><td>Museums</td><td style="text-align:center;">Yes</td><td><a href="https://www.rijksmuseum.nl/en/rijksstudio" target="_blank" rel="noreferrer">rijksmuseum.nl/en/rijksstudio</a> (requires account)</td></tr><tr><td>Harvard Art Museums</td><td>Museums</td><td style="text-align:center;">Yes</td><td><a href="https://harvardartmuseums.org/collections/api" target="_blank" rel="noreferrer">harvardartmuseums.org/collections/api</a> (request form)</td></tr><tr><td>Cooper Hewitt, Smithsonian</td><td>Museums</td><td style="text-align:center;">Yes</td><td><a href="https://collection.cooperhewitt.org/api/" target="_blank" rel="noreferrer">collection.cooperhewitt.org/api</a></td></tr><tr><td>Unsplash</td><td>Photography</td><td style="text-align:center;">Yes</td><td><a href="https://unsplash.com/developers" target="_blank" rel="noreferrer">unsplash.com/developers</a></td></tr><tr><td>Flickr</td><td>Photography</td><td style="text-align:center;">Yes</td><td><a href="https://www.flickr.com/services/api/" target="_blank" rel="noreferrer">flickr.com/services/api</a></td></tr><tr><td>Pixabay</td><td>Photography</td><td style="text-align:center;">Yes</td><td><a href="https://pixabay.com/api/docs/" target="_blank" rel="noreferrer">pixabay.com/api/docs</a></td></tr><tr><td>Pexels</td><td>Photography</td><td style="text-align:center;">Yes</td><td><a href="https://www.pexels.com/api/" target="_blank" rel="noreferrer">pexels.com/api</a></td></tr><tr><td>Noun Project</td><td>Art and Design</td><td style="text-align:center;">Yes</td><td><a href="https://thenounproject.com/developers/" target="_blank" rel="noreferrer">thenounproject.com/developers</a></td></tr><tr><td>Giphy</td><td>Art and Design</td><td style="text-align:center;">Yes</td><td><a href="https://developers.giphy.com/" target="_blank" rel="noreferrer">developers.giphy.com</a></td></tr><tr><td>YouTube (thumbnails)</td><td>Science</td><td style="text-align:center;">Yes</td><td><a href="https://console.cloud.google.com/" target="_blank" rel="noreferrer">console.cloud.google.com</a> — enable YouTube Data API v3</td></tr></tbody></table><h2 id="ai-provider-keys-optional" tabindex="-1">AI provider keys (optional) <a class="header-anchor" href="#ai-provider-keys-optional" aria-label="Permalink to &quot;AI provider keys (optional)&quot;">​</a></h2><p>Analysis already works without any of these — Cloudflare Workers AI (LLaVA 1.5) runs by default. BYOK is for when you want a specific model&#39;s output.</p><table tabindex="0"><thead><tr><th>Provider</th><th style="text-align:center;">Free tier?</th><th>Where to get a key</th></tr></thead><tbody><tr><td>Google Gemini</td><td style="text-align:center;">Yes</td><td><a href="https://aistudio.google.com/app/apikey" target="_blank" rel="noreferrer">aistudio.google.com/app/apikey</a></td></tr><tr><td>Anthropic Claude</td><td style="text-align:center;">Trial credits</td><td><a href="https://console.anthropic.com/" target="_blank" rel="noreferrer">console.anthropic.com</a></td></tr><tr><td>OpenAI</td><td style="text-align:center;">Paid</td><td><a href="https://platform.openai.com/api-keys" target="_blank" rel="noreferrer">platform.openai.com/api-keys</a></td></tr><tr><td>Ollama (local)</td><td style="text-align:center;">Free</td><td>Install <a href="https://ollama.com" target="_blank" rel="noreferrer">ollama.com</a> and set the local URL in the Keys panel</td></tr></tbody></table><h2 id="how-to-add-a-key" tabindex="-1">How to add a key <a class="header-anchor" href="#how-to-add-a-key" aria-label="Permalink to &quot;How to add a key&quot;">​</a></h2><ol><li>Open the app and press <code>k</code> (or click the key icon in the toolbar)</li><li>Find the source in the list</li><li>Paste your key into the input</li><li>It saves to <code>localStorage</code> the moment you stop typing — no submit button</li><li>Close the panel and search. Results from that source start appearing</li></ol><h2 id="key-storage-and-privacy" tabindex="-1">Key storage and privacy <a class="header-anchor" href="#key-storage-and-privacy" aria-label="Permalink to &quot;Key storage and privacy&quot;">​</a></h2><ul><li>Keys are stored in <strong>your browser&#39;s <code>localStorage</code></strong> on <strong>your machine</strong> only</li><li>Each key is sent <strong>only to the API it belongs to</strong> — your Rijksmuseum key goes only to <code>api.rijksmuseum.nl</code></li><li>InspoSearch has <strong>no backend server for search</strong> — there is nowhere for keys to be forwarded</li><li>Clearing browser data removes your keys (and everything else — back them up if you rely on the set)</li><li>Remove a single key by clearing its input field in the Keys panel</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Likely cause</th><th>Fix</th></tr></thead><tbody><tr><td>Source still empty after adding key</td><td>Key invalid, or source disabled by health check</td><td>Test the key directly at the provider&#39;s API docs; then clear the field and re-paste</td></tr><tr><td>Key disappeared</td><td>Browser data cleared</td><td>Re-paste from your notes. Consider keeping a backup list</td></tr><tr><td>401 / Unauthorized in console</td><td>Expired or revoked key</td><td>Generate a new one at the provider</td></tr><tr><td>429 / rate limit errors</td><td>Daily free-tier limit hit</td><td>Wait; or upgrade at the provider if available</td></tr><tr><td>Source works sometimes, fails other times</td><td>Source-side flakiness or our health-check backoff</td><td>Usually self-recovers within a minute</td></tr></tbody></table><h2 id="when-info-insposearch-org-is-live" tabindex="-1">When <code>info@insposearch.org</code> is live <a class="header-anchor" href="#when-info-insposearch-org-is-live" aria-label="Permalink to &quot;When `info@insposearch.org` is live&quot;">​</a></h2><p>We&#39;ll migrate our contact routing off the temporary Gmail address. No user action needed — your keys don&#39;t depend on our email.</p>',20)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
